vectorizer = None
model = None
MODEL_PATH = 'spam_model.pkl'
VECTORIZER_PATH = 'vectorizer.pkl'

def train_model():
    global vectorizer, model
    
    texts = [email[0] for email in sample_emails]
    labels = [email[1] for email in sample_emails]
    
    vectorizer = CountVectorizer(max_features=1000, stop_words='english')
    X = vectorizer.fit_transform(texts)
    
    model = LogisticRegression(max_iter=1000, random_state=42)
    model.fit(X, labels)
    
    with open(MODEL_PATH, 'wb') as f:
        pickle.dump(model, f)
    
    with open(VECTORIZER_PATH, 'wb') as f:
        pickle.dump(vectorizer, f)
    
    print("Model trained and saved successfully")

def load_model():
    global vectorizer, model
    
    if os.path.exists(MODEL_PATH) and os.path.exists(VECTORIZER_PATH):
        with open(MODEL_PATH, 'rb') as f:
            model = pickle.load(f)
        
        with open(VECTORIZER_PATH, 'rb') as f:
            vectorizer = pickle.load(f)
        
        print("Model loaded successfully")
    else:
        print("Model files not found. Training new model...")
        train_model()

@app.route('/predict', methods=['POST'])
def predict():
    try:
        data = request.get_json()
        
        if not data or 'text' not in data:
            return jsonify({'error': 'No text provided'}), 400
        
        email_text = data['text']
        
        if not isinstance(email_text, str) or len(email_text.strip()) == 0:
            return jsonify({'error': 'Invalid email text'}), 400
        
        X = vectorizer.transform([email_text])
        
        spam_probability = model.predict_proba(X)[0][1]
        is_spam = model.predict(X)[0]
        
        response = {
            'spam_probability': float(spam_probability),
            'is_spam': bool(is_spam),
            'text': email_text
        }
        
        return jsonify(response), 200
    
    except Exception as e:
        return jsonify({'error': str(e)}), 500

@app.route('/retrain', methods=['POST'])
def retrain():
    try:
        train_model()
        return jsonify({'message': 'Model retrained successfully'}), 200
    except Exception as e:
        return jsonify({'error': str(e)}), 500

@app.route('/health', methods=['GET'])
def health():
    return jsonify({'status': 'healthy', 'model_loaded': model is not None}), 200

